solution_code:
#include <iostream>

void printRectangleInfo(int width, int height) {
    std::cout << "Perimeter: " << 2 * (width + height) << '\n';
    std::cout << "Area: " << width * height << '\n';
}

int main() {
    int width{};
    int height{};
    std::cin >> width >> height;

    printRectangleInfo(width, height);

    return 0;
}

