solution_code:
#include <iostream>

int weightedAverage(int s1, int w1, int s2, int w2) {
    return (s1 * w1 + s2 * w2) / (w1 + w2);
}

int main() {
    int s1{}, w1{}, s2{}, w2{};
    std::cin >> s1 >> w1 >> s2 >> w2;

    std::cout << weightedAverage(s1, w1, s2, w2) << '\n';

    return 0;
}
